5</span> <span>class</span><span>=</span><span>\"text-white font-bold text-lg mb-4\"</span><span>&gt;</span>অনুসরণ করুন<span>&lt;/</span><span>h5</span><span>&gt;</span></div><div>                <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"flex space-x-4\"</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"hover:text-white\"</span><span>&gt;</span>ফেসবুক<span>&lt;/</span><span>a</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"hover:text-white\"</span><span>&gt;</span>টুইটার<span>&lt;/</span><span>a</span><span>&gt;</span></div><div>                    <span>&lt;</span><span>a</span> <span>href</span><span>=</span><span>\"#\"</span> <span>class</span><span>=</span><span>\"hover:text-white\"</span><span>&gt;</span>লিঙ্কডইন<span>&lt;/</span><span>a</span><span>&gt;</span></div><div>                <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>            <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>        <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>        <span>&lt;</span><span>div</span> <span>class</span><span>=</span><span>\"max-w-6xl mx-auto px-4 mt-8 pt-8 border-t border-gray-800 text-center text-xs\"</span><span>&gt;</span></div><div>            © ২০২৬ আমার ব্লগ ওয়েবসাইট। সর্বস্বত্ব সংরক্ষিত।</div><div>        <span>&lt;/</span><span>div</span><span>&gt;</span></div><div>    <span>&lt;/</span><span>footer</span><span>&gt;</span></div><br><div><span>&lt;/</span><span>body</span><span>&gt;</span></div><div><span>&lt;/</span><span>html</span><span>&gt;</span></div>', '0', NULL, '2026-01-29 02:40:43', '2026-01-29 02:40:43');
